import{_ as p,o as r,c as t,j as e,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"卢修斯14型(重型)激光枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/卢修斯14型(重型)激光枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/卢修斯14型(重型)激光枪.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/卢修斯14型(重型)激光枪.md"};function _(d,a,l,i,c,h){return r(),t("div",null,[...a[0]||(a[0]=[e("h1",{id:"卢修斯14型-重型-激光枪",tabindex:"-1"},[s("卢修斯14型(重型)激光枪 "),e("a",{class:"header-anchor",href:"#卢修斯14型-重型-激光枪","aria-label":'Permalink to "卢修斯14型(重型)激光枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="卢修斯14型-重型-激光枪-1" tabindex="-1">卢修斯14型(重型)激光枪 <a class="header-anchor" href="#卢修斯14型-重型-激光枪-1" aria-label="Permalink to &quot;卢修斯14型(重型)激光枪&quot;">​</a></h1><p>卢修斯14型(重型)激光枪<br> B+4000<br> 科技本质</p><p>卢修斯XIV型激光枪是地狱枪的一个变种，也是克里格死亡军团掷弹兵的标准武器 用来承担精准射击任务，由于射击时巨大的热量，因此在射击时枪如其名（Hot-shot），所以在枪管中还包含了一个热交换管道的冷却系统，加压的冷却剂将通过管道使枪管降温。但是在不射击时，枪管内的冷却系统却使得枪管温度很低，因此普通人可能要戴上手套防止冻伤，地狱枪在建造过程中需要多种先进的组件，包括增强合金枪管，以承受在发射过程中产生的更大的热量，因此，帝国中只有少数铸造世界拥有生产这些强大武器的技术诀窍或必要的材料，所以也仅仅发给那些经验丰富的战士。</p><p>这种枪的使用者通常会背着一个大背包，背包里有一个独立的电源，用来给地狱枪供能并提供更多的伤害输出，在无标准电源包供弹时，该地狱枪本身的所装载的电池只能支持12发射击。和标准的激光枪不一样的是，其配备了一个安全装置，在过热时会自动切断电源，直到枪管再次下降到安全范围内，所以卢修斯14型(重型)激光枪仅可以在半自动模式下工作，每次扣动扳机就发射一枪。</p><p>重量：3.7KG</p><p>长度：1400毫米</p><p>体积：3</p><p>专业：自动步枪</p><p>伤害：20L<br> 基础射程：200米</p><p>弹夹类型：使用标准能量电池供能（可射击12发）</p><p>射击类型：单发</p><p>瞄具：先进光学瞄准器</p><p>先进光学瞄准器 ：卢修斯14型(重型)激光枪拥有一个复杂的先进瞄准镜，包括一个4倍镜以进一步增加武器的精度，这意味着使用该武器瞄准时，人物的【视距】提升四倍，这并不意味着人物的敏感范围的到提升，但仅在使用视觉定位时，人物可以定位四倍自身敏感范围距离内的敌人。</p><p>先进激光产生系统：该枪的射击系统允许激光在60兆赫的能量范围内运行，其强大的能量和穿透力，甚至可以击穿地狱惧兽的护甲，卢修斯14型(重型)激光枪 还具有【能量武器】，【超级贯穿】特性。<br> ------------------------------------------------------------------------------------------------</p><p>标准能量背包<br> 价格：1250分</p><p>重量：15kg</p><p>长度：800*700*200毫米</p><p>体积：3</p><p>在由能量背包供能时，卢修斯14型(重型)激光枪在正常的射击功率和武器状态下可以射击200发，当标准能量背包消耗殆尽后，人物可以使用能量背包提供的一个快速充电器，该充电器可以适配任意电源。仅需一个小时就能充满，且在该能量背包供能下，卢修斯14型(重型)激光枪可以使用【短点射】。</p><p>值得注意的是，虽然标准能量背包的电池组，可以向激光枪能源电池一样直接依靠热电转换进行充电，但这么做无异有着损坏电源的风险，考虑到其昂贵的造价，如果你看到你的任何队友在这么做，那么不要犹豫，请举起你手中的武器，像是消灭异端一样消灭他。</p><p>注1：应当在在开枪后立刻向政委和军需官报告此事。<br> 注2：当一件工作需要不只一个人或部门协作完成时，那就永远不要自己处理。永远准备好说“这个要看其他同事/部门的情况”<br> 注3：记住上一件事。</p><p>#### 每日一思 ####<br> “确定你的目标，不管其他所有，集火在他身上。当他被摧毁时再选择下一个目标。这就是保证获胜的方式！”</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',24)])])}const m=p(o,[["render",_]]);export{f as __pageData,m as default};
